{
  "number": "18",
  "title": "Pregnancy and maternity discrimination: work cases",
  "subsections": {
    "section-18-1": {
      "number": "(1)",
      "content": "This section has effect for the purposes of the application of Part 5 (work) to the protected characteristic of pregnancy and maternity."
    },
    "section-18-2": {
      "number": "(2)",
      "content": "A person (A) discriminates against a woman if, inor afterthe protected period in relation to a pregnancy of hers, A treats her unfavourably —",
      "subitems": {
        "section-18-2-a": {
          "number": "(a)",
          "content": "because of the pregnancy, or"
        },
        "section-18-2-b": {
          "number": "(b)",
          "content": "because of illness suffered by herin that protected period as a result of the pregnancy."
        }
      }
    },
    "section-18-3": {
      "number": "(3)",
      "content": "A person (A) discriminates against a woman if A treats her unfavourably because she is on compulsory maternity leaveor on equivalent compulsory maternity leave."
    },
    "section-18-4": {
      "number": "(4)",
      "content": "A person (A) discriminates against a woman if A treats her unfavourably because she is exercising or seeking to exercise, or has exercised or sought to exercise, the right to ordinary or additional maternity leaveor a right to equivalent maternity leave."
    },
    "section-18-5": {
      "number": "(5)",
      "content": ". . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . ."
    },
    "section-18-6": {
      "number": "(6)",
      "content": "The protected period, in relation to a woman's pregnancy, begins when the pregnancy begins, and ends—",
      "subitems": {
        "section-18-6-a": {
          "number": "(a)",
          "content": "if she has the right to ordinary and additional maternity leave, at the end of the additional maternity leave period or (if earlier) when she returns to work after the pregnancy;"
        },
        "section-18-6-aa": {
          "number": "(aa)",
          "content": "if she does not have that right, but has a right to equivalent maternity leave, at the end of that leave period, or (if earlier) when she returns to work after the pregnancy;"
        },
        "section-18-6-b": {
          "number": "(b)",
          "content": "if she does not havea right as described in paragraph (a) or (aa), at the end of the period of 2 weeks beginning with the end of the pregnancy."
        }
      }
    },
    "section-18-6A": {
      "number": "(6A)",
      "content": "For the purposes of this section—",
      "lists": [
        {
          "type": "ul",
          "items": [
            "“ equivalent compulsory maternity leave ” means a period of leave— (a) which is of a substantially similar nature (regardless of its length) to compulsory maternity leave, and (b) which is provided for under a statutory or contractual scheme;",
            "“ equivalent maternity leave ” means a period of leave— (a) which is of a substantially similar nature (regardless of its length) to ordinary or additional maternity leave or both, and (b) which is provided for under a statutory or contractual scheme."
          ]
        }
      ]
    },
    "section-18-7": {
      "number": "(7)",
      "content": "Section 13, so far as relating to sex discrimination, does not apply to treatment of a woman in so far as—",
      "subitems": {
        "section-18-7-a": {
          "number": "(a)",
          "content": "it is inor afterthe protected period in relation to her and is for a reason mentioned in paragraph (a) or (b) of subsection (2), or"
        },
        "section-18-7-b": {
          "number": "(b)",
          "content": "it is for a reason mentioned in subsection (3) or (4)."
        }
      }
    }
  }
}

