{
  "number": "43",
  "title": "Child assessment orders.",
  "subsections": {
    "section-43-1": {
      "number": "(1)",
      "content": "On the application of a local authority or authorised person for an order to be made under this section with respect to a child, the court may make the order if, but only if, it is satisfied that—",
      "subitems": {
        "section-43-1-a": {
          "number": "(a)",
          "content": "the applicant has reasonable cause to suspect that the child is suffering, or is likely to suffer, significant harm;"
        },
        "section-43-1-b": {
          "number": "(b)",
          "content": "an assessment of the state of the child’s health or development, or of the way in which he has been treated, is required to enable the applicant to determine whether or not the child is suffering, or is likely to suffer, significant harm; and"
        },
        "section-43-1-c": {
          "number": "(c)",
          "content": "it is unlikely that such an assessment will be made, or be satisfactory, in the absence of an order under this section."
        }
      }
    },
    "section-43-2": {
      "number": "(2)",
      "content": "In this Act “a child assessment order” means an order under this section."
    },
    "section-43-3": {
      "number": "(3)",
      "content": "A court may treat an application under this section as an application for an emergency protection order."
    },
    "section-43-4": {
      "number": "(4)",
      "content": "No court shall make a child assessment order if it is satisfied—",
      "subitems": {
        "section-43-4-a": {
          "number": "(a)",
          "content": "that there are grounds for making an emergency protection order with respect to the child; and"
        },
        "section-43-4-b": {
          "number": "(b)",
          "content": "that it ought to make such an order rather than a child assessment order."
        }
      }
    },
    "section-43-5": {
      "number": "(5)",
      "content": "A child assessment order shall—",
      "subitems": {
        "section-43-5-a": {
          "number": "(a)",
          "content": "specify the date by which the assessment is to begin; and"
        },
        "section-43-5-b": {
          "number": "(b)",
          "content": "have effect for such period, not exceeding 7 days beginning with that date, as may be specified in the order."
        }
      }
    },
    "section-43-6": {
      "number": "(6)",
      "content": "Where a child assessment order is in force with respect to a child it shall be the duty of any person who is in a position to produce the child—",
      "subitems": {
        "section-43-6-a": {
          "number": "(a)",
          "content": "to produce him to such person as may be named in the order; and"
        },
        "section-43-6-b": {
          "number": "(b)",
          "content": "to comply with such directions relating to the assessment of the child as the court thinks fit to specify in the order."
        }
      }
    },
    "section-43-7": {
      "number": "(7)",
      "content": "A child assessment order authorises any person carrying out the assessment, or any part of the assessment, to do so in accordance with the terms of the order."
    },
    "section-43-8": {
      "number": "(8)",
      "content": "Regardless of subsection (7), if the child is of sufficient understanding to make an informed decision he may refuse to submit to a medical or psychiatric examination or other assessment."
    },
    "section-43-9": {
      "number": "(9)",
      "content": "The child may only be kept away from home—",
      "subitems": {
        "section-43-9-a": {
          "number": "(a)",
          "content": "in accordance with directions specified in the order;"
        },
        "section-43-9-b": {
          "number": "(b)",
          "content": "if it is necessary for the purposes of the assessment; and"
        },
        "section-43-9-c": {
          "number": "(c)",
          "content": "for such period or periods as may be specified in the order."
        }
      }
    },
    "section-43-10": {
      "number": "(10)",
      "content": "Where the child is to be kept away from home, the order shall contain such directions as the court thinks fit with regard to the contact that he must be allowed to have with other persons while away from home."
    },
    "section-43-11": {
      "number": "(11)",
      "content": "Any person making an application for a child assessment order shall take such steps as are reasonably practicable to ensure that notice of the application is given to—",
      "subitems": {
        "section-43-11-a": {
          "number": "(a)",
          "content": "the child’s parents;"
        },
        "section-43-11-b": {
          "number": "(b)",
          "content": "any person who is not a parent of his but who has parental responsibility for him;"
        },
        "section-43-11-c": {
          "number": "(c)",
          "content": "any other person caring for the child;"
        },
        "section-43-11-d": {
          "number": "(d)",
          "content": "any person named in a child arrangements order as a person with whom the child is to spend time or otherwise have contact;"
        },
        "section-43-11-e": {
          "number": "(e)",
          "content": "any person who is allowed to have contact with the child by virtue of an order under section 34; and"
        },
        "section-43-11-f": {
          "number": "(f)",
          "content": "the child,"
        }
      },
      "additional_content": "before the hearing of the application."
    },
    "section-43-12": {
      "number": "(12)",
      "content": "Rules of court may make provision as to the circumstances in which—",
      "subitems": {
        "section-43-12-a": {
          "number": "(a)",
          "content": "any of the persons mentioned in subsection (11); or"
        },
        "section-43-12-b": {
          "number": "(b)",
          "content": "such other person as may be specified in the rules,"
        }
      },
      "additional_content": "may apply to the court for a child assessment order to be varied or discharged."
    },
    "section-43-13": {
      "number": "(13)",
      "content": "In this section “authorised person” means a person who is an authorised person for the purposes of section 31."
    }
  }
