          "number": "(b)",
          "content": "his physical, emotional and educational needs;"
        },
        "section-1-3-c": {
          "number": "(c)",
          "content": "the likely effect on him of any change in his circumstances;"
        },
        "section-1-3-d": {
          "number": "(d)",
          "content": "his age, sex, background and any characteristics of his which the court considers relevant;"
        },
        "section-1-3-e": {
          "number": "(e)",
          "content": "any harm which he has suffered or is at risk of suffering;"
        },
        "section-1-3-f": {
          "number": "(f)",
          "content": "how capable each of his parents, and any other person in relation to whom the court considers the question to be relevant, is of meeting his needs;"
        },
        "section-1-3-g": {
          "number": "(g)",
          "content": "the range of powers available to the court under this Act in the proceedings in question."
        }
      }
